"use client";

import { useEffect, useRef, useState, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import dynamic from "next/dynamic";
import Link from "next/link";
import type { ExcalidrawWrapperHandle } from "@/components/ExcalidrawWrapper";
import type { Board } from "@/lib/types";
import { getBoard, saveBoard } from "@/lib/storage";

// Dynamically import ExcalidrawWrapper (it is client-only)
const ExcalidrawWrapper = dynamic(
  () => import("@/components/ExcalidrawWrapper"),
  { ssr: false }
);

const AUTOSAVE_DELAY = 2000; // ms

export default function BoardPage() {
  const { id } = useParams<{ id: string }>();
  const router = useRouter();
  const wrapperRef = useRef<ExcalidrawWrapperHandle>(null);
  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [board, setBoard] = useState<Board | null>(null);
  const [notFound, setNotFound] = useState(false);
  const [saveStatus, setSaveStatus] = useState<"idle" | "saving" | "saved">(
    "idle"
  );
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    if (!id) return;
    const b = getBoard(id);
    if (!b) {
      setNotFound(true);
    } else {
      setBoard(b);
    }
  }, [id]);

  const persistScene = useCallback(() => {
    if (!wrapperRef.current || !board) return;
    const data = wrapperRef.current.getSceneData();
    if (!data) return;

    setSaveStatus("saving");

    const updated: Board = {
      ...board,
      elements: JSON.stringify(data.elements),
      appState: JSON.stringify({
        viewBackgroundColor: data.appState.viewBackgroundColor,
        currentItemFontFamily: data.appState.currentItemFontFamily,
        currentItemFontSize: data.appState.currentItemFontSize,
        zoom: data.appState.zoom,
        scrollX: data.appState.scrollX,
        scrollY: data.appState.scrollY,
      }),
      files: JSON.stringify(data.files),
      updatedAt: Date.now(),
    };

    saveBoard(updated);
    setBoard(updated);
    setSaveStatus("saved");

    // Reset "saved" status after a short delay
    setTimeout(() => setSaveStatus("idle"), 2000);
  }, [board]);

  // Auto-save on every change with debounce
  const handleChange = useCallback(() => {
    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(persistScene, AUTOSAVE_DELAY);
  }, [persistScene]);

  // Manual save on Ctrl/Cmd+S
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if ((e.ctrlKey || e.metaKey) && e.key === "s") {
        e.preventDefault();
        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
        persistScene();
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [persistScene]);

  async function handleCopyShareLink() {
    if (!board) return;
    if (!board.isPublic) {
      // Enable sharing first
      const updated: Board = { ...board, isPublic: true, updatedAt: Date.now() };
      saveBoard(updated);
      setBoard(updated);
    }
    const url = `${window.location.origin}/shared/${board.shareToken}`;
    await navigator.clipboard.writeText(url);
    setCopied(true);
    setTimeout(() => setCopied(false), 2500);
  }

  if (notFound) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50">
        <h1 className="text-2xl font-bold text-gray-700 mb-4">
          Board not found
        </h1>
        <Link
          href="/"
          className="text-blue-600 hover:underline text-sm"
        >
          ← Back to Dashboard
        </Link>
      </div>
    );
  }

  if (!board) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600" />
      </div>
    );
  }

  let initialData = null;
  try {
    const elements = JSON.parse(board.elements);
    const appState = JSON.parse(board.appState);
    const files = JSON.parse(board.files);
    initialData = { elements, appState, files };
  } catch {
    initialData = null;
  }

  return (
    <div className="h-screen flex flex-col">
      {/* Top bar */}
      <header className="flex-none h-12 bg-white border-b border-gray-200 flex items-center px-4 gap-3 z-30">
        <Link
          href="/"
          className="text-gray-500 hover:text-gray-800 transition-colors"
          title="Back to Dashboard"
        >
          <svg
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 20 20"
            fill="currentColor"
            className="w-5 h-5"
          >
            <path
              fillRule="evenodd"
              d="M17 10a.75.75 0 01-.75.75H5.612l4.158 3.96a.75.75 0 11-1.04 1.08l-5.5-5.25a.75.75 0 010-1.08l5.5-5.25a.75.75 0 111.04 1.08L5.612 9.25H16.25A.75.75 0 0117 10z"
              clipRule="evenodd"
            />
          </svg>
        </Link>

        <span className="text-sm font-medium text-gray-800 truncate max-w-xs">
          {board.title}
        </span>

        <div className="ml-auto flex items-center gap-3">
          {/* Save status */}
          <span className="text-xs text-gray-400">
            {saveStatus === "saving"
              ? "Saving…"
              : saveStatus === "saved"
              ? "✓ Saved"
              : ""}
          </span>

          {/* Share button */}
          <button
            onClick={handleCopyShareLink}
            className="inline-flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg border border-gray-300 hover:bg-gray-50 text-gray-700 transition-colors"
            title={board.isPublic ? "Copy share link" : "Enable sharing & copy link"}
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 20 20"
              fill="currentColor"
              className="w-3.5 h-3.5"
            >
              <path d="M13 4.5a2.5 2.5 0 11.702 1.737L6.97 9.604a2.518 2.518 0 010 .792l6.733 3.367a2.5 2.5 0 11-.671 1.341l-6.733-3.367a2.5 2.5 0 110-3.475l6.733-3.366A2.52 2.52 0 0113 4.5z" />
            </svg>
            {copied ? "Copied!" : "Share"}
          </button>

          {/* Manual save */}
          <button
            onClick={persistScene}
            className="inline-flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-blue-600 hover:bg-blue-700 text-white transition-colors"
          >
            Save
          </button>
        </div>
      </header>

      {/* Canvas */}
      <div className="flex-1 relative">
        <ExcalidrawWrapper
          ref={wrapperRef}
          initialData={initialData}
          onChange={handleChange}
        />
      </div>
    </div>
  );
}
